clear; clc; close all;

% ========================================================================
% TASK 1B - HARDWARE / REAL-TIME ECG FREQUENCY DOMAIN ANALYSIS
%
% Use this after the ECG dashboard saves one of these files:
%   ECG_FFT_Window_*.csv
%   ECG_FFT_Window_*.mat
%
% Required outputs generated by this script:
% Output 4a : full magnitude spectrum FFT
% Output 5a : zoomed spectrum from 0-50 Hz
% Output 6a : annotated spectrum with P/T band, QRS band, and noise peaks
% Output 7a : comparison table, RR BPM vs frequency-domain BPM
% Output 8a : written commentary
% Output 9a : hardware/acquisition information table
%
% This version follows the same logical structure as the dataset Task 1B
% script, but it is adapted for real-time hardware ECG window files.
% ========================================================================

%% ----------------------- SETTINGS --------------------------------------
outputFolder = fullfile(pwd, 'Task1B_hardware_outputs');
if ~exist(outputFolder, 'dir')
    mkdir(outputFolder);
end

mainsHz   = 50;       % Pakistan mains frequency
fallbackFs = 250;     % Default dashboard sampling rate

fprintf('\n============================================================\n');
fprintf('TASK 1B - HARDWARE / REAL-TIME ECG FREQUENCY DOMAIN ANALYSIS\n');
fprintf('============================================================\n');

%% ----------------------- LOAD HARDWARE ECG WINDOW ----------------------
% Select the CSV/MAT file saved by the ECG dashboard. The dashboard usually
% saves a 20 s ECG segment for FFT as ECG_FFT_Window_*.csv or .mat.

[ecgRaw, Fs, meta] = load_hardware_ecg_window(fallbackFs);

ecgRaw = double(ecgRaw(:));
ecgRaw = ecgRaw(isfinite(ecgRaw));

if numel(ecgRaw) < round(2 * Fs)
    error('The selected ECG window is too short for FFT and R-peak analysis.');
end

N = numel(ecgRaw);
time = (0:N-1)' / Fs;
meta.durationSec = N / Fs;
meta.Fs = Fs;

fprintf('Loaded hardware ECG window: %s\n', meta.recordID);
fprintf('Sampling rate: %.2f Hz\n', Fs);
fprintf('Segment duration: %.2f seconds\n', meta.durationSec);
fprintf('Patient/subject: %s | Age: %s | Notes: %s\n', ...
    meta.patientName, meta.patientAge, meta.patientNotes);

%% ----------------------- FILTER / PRE-PROCESS --------------------------
% Same filtering logic as the dataset script: baseline correction, high-pass,
% low-pass, notch filtering, normalization, and polarity correction.

F = ecg_design_filters(Fs, mainsHz, 0.5, 40, 35);
[ecgClean, stages] = ecg_apply_classical_filters(ecgRaw, Fs, F); 

%% ----------------------- R-PEAK BPM + HRV ------------------------------
[rLocs, rAmps] = ecg_detect_rpeaks(ecgClean, Fs);
[bpmRR, rmssd, sdnn, rrMs] = ecg_bpm_hrv(rLocs, Fs);

fig1 = figure('Name','Hardware ECG with R-peaks', ...
    'Color','w', ...
    'Position',[80 80 1100 550]);

plot(time, ecgClean, 'LineWidth', 1.2);
hold on; grid on;

if ~isempty(rLocs)
    plot(time(rLocs), rAmps, 'rv', 'MarkerFaceColor','r');
end

xlabel('Time (s)');
ylabel('Normalized amplitude');
title(sprintf('Hardware ECG after preprocessing: %s', meta.recordID), ...
    'Interpreter','none');

if ~isempty(rLocs)
    legend('Clean ECG','Detected R-peaks');
else
    legend('Clean ECG');
end

save_figure(fig1, fullfile(outputFolder,'Output3a_hardware_Rpeaks_HR_HRV.png'));

%% ----------------------- FFT FEATURES ----------------------------------
featRaw   = ecg_fft_features(ecgRaw, Fs, mainsHz);
featClean = ecg_fft_features(ecgClean, Fs, mainsHz);

f   = featClean.f;
mag = featClean.mag;

bpmFreq = featClean.hrBpm;

if isnan(bpmRR) || isnan(bpmFreq)
    percentError = NaN;
else
    percentError = abs(bpmRR - bpmFreq) / max(abs(bpmRR), eps) * 100;
end

%% ----------------------- OUTPUT 4a: FULL FFT ---------------------------
fig2 = figure('Name','Output 4a Hardware FFT Magnitude Spectrum', ...
    'Color','w', ...
    'Position',[80 80 1100 600]);

plot(f, mag, 'LineWidth', 1.3);
grid on;
xlabel('Frequency (Hz)');
ylabel('|X(f)| Magnitude');
title('Output 4a: Hardware ECG Single-Sided FFT Magnitude Spectrum');
xlim([0 Fs/2]);

save_figure(fig2, fullfile(outputFolder,'Output4a_hardware_full_fft.png'));

%% ----------------------- OUTPUT 5a: 0-50 Hz FFT ------------------------
fig3 = figure('Name','Output 5a Hardware Zoomed FFT 0-50 Hz', ...
    'Color','w', ...
    'Position',[80 80 1100 600]);

keep50 = f <= min(50, Fs/2);
plot(f(keep50), mag(keep50), 'LineWidth', 1.4);
grid on;
xlabel('Frequency (Hz)');
ylabel('|X(f)| Magnitude');
title('Output 5a: Hardware ECG Zoomed FFT Spectrum, 0-50 Hz');
xlim([0 min(50, Fs/2)]);

save_figure(fig3, fullfile(outputFolder,'Output5a_hardware_zoom_0_50Hz.png'));

%% ----------------------- OUTPUT 6a: ANNOTATED FFT ----------------------
fig4 = figure('Name','Output 6a Hardware Annotated Spectrum', ...
    'Color','w', ...
    'Position',[80 80 1150 650]);

plot(f(keep50), mag(keep50), 'LineWidth', 1.4);
grid on; hold on;
xlabel('Frequency (Hz)');
ylabel('|X(f)| Magnitude');
title('Output 6a: Annotated Frequency Spectrum of Hardware ECG');
xlim([0 min(50, Fs/2)]);

add_vline_label(gca, 0.5,  'Baseline wander < 0.5 Hz', '--');
add_vline_label(gca, 10,   'P/T morphology approx. 0.5-10 Hz', '--');
add_vline_label(gca, 40,   'QRS high-frequency energy approx. 10-40 Hz', '--');

if mainsHz <= min(50, Fs/2)
    add_vline_label(gca, mainsHz, sprintf('%d Hz power-line region', mainsHz), ':');
end

ampRef = max(mag(keep50));
if ~isfinite(ampRef) || ampRef <= 0
    ampRef = 1;
end

if isfinite(featClean.hrPeakHz) && featClean.hrPeakHz <= min(50, Fs/2)
    plot(featClean.hrPeakHz, featClean.hrPeakMag, 'rv', ...
        'MarkerFaceColor','r', ...
        'MarkerSize',8);
    text(featClean.hrPeakHz, featClean.hrPeakMag + 0.05*ampRef, ...
        sprintf(' HR peak %.2f Hz = %.1f BPM', featClean.hrPeakHz, bpmFreq), ...
        'FontWeight','bold', ...
        'Color','r');
end

if isfinite(featClean.ptPeakHz) && featClean.ptPeakHz <= min(50, Fs/2)
    plot(featClean.ptPeakHz, featClean.ptPeakMag, 'bs', ...
        'MarkerFaceColor','c', ...
        'MarkerSize',7);
    text(featClean.ptPeakHz, featClean.ptPeakMag + 0.09*ampRef, ...
        sprintf(' P/T low-band peak %.2f Hz', featClean.ptPeakHz), ...
        'FontWeight','bold', ...
        'Color','b');
end

if isfinite(featClean.qrsPeakHz) && featClean.qrsPeakHz <= min(50, Fs/2)
    plot(featClean.qrsPeakHz, featClean.qrsPeakMag, 'ko', ...
        'MarkerFaceColor','y', ...
        'MarkerSize',7);
    text(featClean.qrsPeakHz, featClean.qrsPeakMag + 0.13*ampRef, ...
        sprintf(' QRS HF peak %.2f Hz', featClean.qrsPeakHz), ...
        'FontWeight','bold', ...
        'Color','k');
end

if isfinite(featClean.noisePeakHz) && featClean.noisePeakHz <= min(50, Fs/2)
    plot(featClean.noisePeakHz, featClean.noisePeakMag, 'md', ...
        'MarkerFaceColor','m', ...
        'MarkerSize',7);
    text(featClean.noisePeakHz, featClean.noisePeakMag + 0.17*ampRef, ...
        sprintf(' Noise peak %.2f Hz', featClean.noisePeakHz), ...
        'FontWeight','bold', ...
        'Color','m');
end

save_figure(fig4, fullfile(outputFolder,'Output6a_hardware_annotated_fft.png'));

%% ----------------------- OUTPUT 7a: COMPARISON TABLE -------------------
comparisonTable = table( ...
    {'RR intervals'; 'Frequency-domain FFT'}, ...
    {sprintf('Median RR interval from %d detected R-peaks', numel(rLocs)); ...
     sprintf('Dominant HR peak = %.3f Hz', featClean.hrPeakHz)}, ...
    {'HR = 60 / median(RR)'; 'HR = dominant frequency x 60'}, ...
    [bpmRR; bpmFreq], ...
    [NaN; featClean.hrPeakHz], ...
    [0; percentError], ...
    'VariableNames', { ...
    'Method', ...
    'Input_Used', ...
    'Formula', ...
    'Heart_Rate_BPM', ...
    'Frequency_Hz', ...
    'Difference_from_RR_percent'});

writetable(comparisonTable, fullfile(outputFolder,'Output7a_hardware_hr_comparison.csv'));

disp('Output 7a: Hardware heart-rate comparison table');
disp(comparisonTable);

fig5 = figure('Name','Output 7a Hardware Comparison Table', ...
    'Color','w', ...
    'Position',[120 120 1150 320]);

annotation(fig5,'textbox',[0.02 0.91 0.96 0.08], ...
    'String','Output 7a: HR Comparison, Time Domain vs Frequency Domain', ...
    'EdgeColor','none', ...
    'FontWeight','bold', ...
    'FontSize',13, ...
    'HorizontalAlignment','center');

uitable('Parent', fig5, ...
    'Data', safeCellForUitable(comparisonTable), ...
    'ColumnName', cellstr(comparisonTable.Properties.VariableNames), ...
    'Units', 'normalized', ...
    'Position', [0.02 0.12 0.96 0.72]);

save_figure(fig5, fullfile(outputFolder,'Output7a_hardware_hr_comparison_table.png'));

%% ----------------------- OUTPUT 8a: COMMENTARY -------------------------
commentary = generate_hardware_commentary(meta, featRaw, featClean, bpmRR, bpmFreq, percentError);

fid = fopen(fullfile(outputFolder,'Output8a_hardware_frequency_commentary.txt'), 'w');
fprintf(fid, '%s\n', commentary);
fclose(fid);

fprintf('\nOutput 8a commentary:\n%s\n', commentary);

%% ----------------------- OUTPUT 9a: HARDWARE INFO TABLE ----------------
infoTable = table( ...
    {char(meta.source)}, ...
    {char(meta.recordID)}, ...
    Fs, ...
    meta.durationSec, ...
    {char(meta.patientName)}, ...
    {char(meta.patientAge)}, ...
    {char(meta.patientNotes)}, ...
    {char(meta.signalType)}, ...
    {char(meta.localFile)}, ...
    'VariableNames', { ...
    'Source', ...
    'Record_ID_or_File', ...
    'Sampling_Rate_Hz', ...
    'Segment_Duration_s', ...
    'Patient_Name', ...
    'Age', ...
