writetable(infoTable, fullfile(outputFolder,'Output9a_hardware_information_table.csv'));

disp('Output 9a: Hardware information table');
disp(infoTable);

fig6 = figure('Name','Output 9a Hardware Information', ...
    'Color','w', ...
    'Position',[100 100 1250 310]);

annotation(fig6,'textbox',[0.02 0.91 0.96 0.08], ...
